"use client"

import type { FC, RefObject } from "react"
import type {
  HTMLStyledProps,
  NoticeConfig,
  NoticePlacement,
  ThemeProps,
} from "@yamada-ui/react"
import type { NoticeStyle } from "./notice.style"
import { createContext, createRef, use, useId, useMemo, useRef } from "react"
import { Portal } from "../portal"
import { NoticeRoot, PLACEMENT_MAP } from "./notice"

export interface NoticeProviderProps
  extends HTMLStyledProps, NoticeConfig, ThemeProps<NoticeStyle> {
  /**
   * Container ref for the portal.
   */
  containerRef?: RefObject<HTMLElement>
}

interface NoticeState {
  limit: number
  placement: NoticePlacement
}

export interface NoticeMethods {
  getId: (placement: NoticePlacement) => string
  getLimit: (placement: NoticePlacement) => number
  updateLimit: (state: NoticeState) => void
}

interface NoticeContext extends NoticeMethods {}

const NoticeContext = createContext({} as NoticeContext)

export type Controller = ReturnType<typeof createController>

const createController = () => ({
  getLimit: createRef<NoticeMethods["getLimit"]>(),
  updateLimit: createRef<NoticeMethods["updateLimit"]>(),
})

const createMethods = (
  id: string,
  refs: {
    [K in NoticePlacement]?: RefObject<Controller>
  },
  defaultLimit: number,
): NoticeMethods => ({
  getId: (placement) => {
    return `${id}-${placement}`
  },
  getLimit: (placement) => {
    const method = refs[placement]?.current.getLimit.current

    return method?.(placement) ?? defaultLimit
  },
  updateLimit: (state) => {
    const { placement } = state
    const method = refs[placement]?.current.updateLimit.current

    method?.(state)
  },
})

export const NoticeProvider: FC<NoticeProviderProps> = ({
  children,
  containerRef,
  expand = false,
  limit = 3,
}) => {
  const placementMap = useRef<{
    [K in NoticePlacement]?: RefObject<Controller>
  }>({})
  const id = useId()

  const value = useMemo(
    () => ({ ...createMethods(id, placementMap.current, limit) }),
    [id, limit],
  )

  const components = useMemo(() => {
    return (Object.keys(PLACEMENT_MAP) as NoticePlacement[]).map(
      (placement) => {
        if (!placementMap.current[placement])
          placementMap.current[placement] = { current: createController() }

        return (
          <NoticeRoot
            key={placement}
            ref={placementMap.current[placement]}
            expand={expand}
            limit={limit}
            placement={placement}
          />
        )
      },
    )
  }, [limit, expand])

  return (
    <NoticeContext value={value}>
      {children}
      <Portal containerRef={containerRef}>{components}</Portal>
    </NoticeContext>
  )
}

export const useNoticeContext = (): NoticeContext => {
  const context = use(NoticeContext)

  return context
}

import { defineComponentSlotStyle } from "@yamada-ui/react"

export const noticeStyle = defineComponentSlotStyle({
  base: {
    closeButton: {
      "&:is([data-variant='plain'], [data-variant='island'])": {
        colorScheme: "mono!",
      },
      "&:is([data-variant='solid'])": {
        color: "colorScheme.contrast!",
        _hover: { bg: "colorScheme.solid!" },
      },
      fontSize: "md!",
      minBoxSize: "6!",
      position: "absolute",
      right: "3",
      top: "2.5",
    },
    content: {
      "&[data-close-button]": { pe: "6" },
      display: "flex",
      flex: "1",
      flexDirection: "column",
      gap: "1",
    },
    item: {
      minW: "sm",
      position: "relative",
    },
    root: {
      "--mobile-offset": "{spaces.md}",
      "--offset": "{spaces.lg}",
    },
  },
})

export type NoticeStyle = typeof noticeStyle

import { page, renderHook } from "#test/browser"
import { useNotice } from "./use-notice"

async function expectNoticeVisible(text: string) {
  await expect.element(page.getByText(text)).toBeInTheDocument()
}

async function expectNoticeHidden(text: string) {
  await expect.poll(() => page.getByText(text).query()).toBeNull()
}

describe("useNotice", () => {
  test("creates a notice with default options", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      description: "Test Description",
      title: "Test Notice",
    })

    await expectNoticeVisible("Test Notice")
    await expectNoticeVisible("Test Description")
  })

  test("creates a notice with a specific status", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      status: "success",
      title: "Success Notice",
    })

    await expectNoticeVisible("Success Notice")
  })

  test("creates a notice with a loading scheme", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      loadingScheme: "oval",
      title: "Loading Notice",
    })

    await expectNoticeVisible("Loading Notice")
  })

  test("closes a specific notice by id", async () => {
    const { result } = await renderHook(() => useNotice())

    const noticeId = result.current({
      duration: null,
      title: "Closeable Notice",
    })

    await expectNoticeVisible("Closeable Notice")

    result.current.close(noticeId)

    await expectNoticeHidden("Closeable Notice")
  })

  test("closes all notices", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      duration: null,
      title: "Notice 1",
    })
    result.current({
      duration: null,
      title: "Notice 2",
    })

    await expectNoticeVisible("Notice 1")
    await expectNoticeVisible("Notice 2")

    result.current.closeAll()

    await expectNoticeHidden("Notice 1")
    await expectNoticeHidden("Notice 2")
  })

  test("updates an existing notice", async () => {
    const { result } = await renderHook(() => useNotice())

    const noticeId = result.current({
      duration: null,
      title: "Original Notice",
    })

    await expectNoticeVisible("Original Notice")

    result.current.update(noticeId, {
      duration: null,
      title: "Updated Notice",
    })

    await expectNoticeVisible("Updated Notice")
  })

  test("creates a notice with custom placement", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      placement: "end-end",
      title: "Bottom Right Notice",
    })

    await expectNoticeVisible("Bottom Right Notice")
  })

  test("creates a notice with custom limit", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      limit: 5,
      title: "Limited Notice",
    })

    await expectNoticeVisible("Limited Notice")
  })

  test("updates limit and retrieves the updated limit", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      limit: 10,
      placement: "end-end",
      title: "First Limit Notice",
    })

    await expectNoticeVisible("First Limit Notice")

    result.current({
      limit: 10,
      placement: "end-end",
      title: "Second Limit Notice",
    })

    await expectNoticeVisible("Second Limit Notice")
  })

  test("creates a notice with closeStrategy as a string", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      closeStrategy: "button",
      title: "Button Close Notice",
    })

    await expectNoticeVisible("Button Close Notice")
  })

  test("creates a notice with duration", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      duration: 5000,
      title: "Timed Notice",
    })

    await expectNoticeVisible("Timed Notice")
  })

  test("creates a notice without icon", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      title: "No Icon Notice",
      withIcon: false,
    })

    await expectNoticeVisible("No Icon Notice")
  })

  test("creates a notice with closable and button close strategy", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      closable: true,
      closeStrategy: "button",
      duration: null,
      title: "Closeable Button Notice",
    })

    await expectNoticeVisible("Closeable Button Notice")

    const closeButton = page.getByRole("button", { name: /close/i })

    await expect.element(closeButton).toBeInTheDocument()
    ;(closeButton.element() as HTMLElement).click()

    await expectNoticeHidden("Closeable Button Notice")
  })

  test("creates a notice with click close strategy", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      closable: true,
      closeStrategy: "click",
      duration: null,
      title: "Click Close Notice",
    })

    await expectNoticeVisible("Click Close Notice")
    ;(page.getByText("Click Close Notice").element() as HTMLElement).click()

    await expectNoticeHidden("Click Close Notice")
  })

  test("uses default options from hook arguments", async () => {
    const { result } = await renderHook(() =>
      useNotice({
        placement: "end-start",
        status: "warning",
      }),
    )

    result.current({
      title: "Default Options Notice",
    })

    await expectNoticeVisible("Default Options Notice")
  })

  test("creates a notice with closable false", async () => {
    const { result } = await renderHook(() => useNotice())

    result.current({
      closable: false,
      closeStrategy: "button",
      duration: null,
      title: "Non-closable Notice",
    })

    await expectNoticeVisible("Non-closable Notice")
    await expect
      .poll(() => page.getByRole("button", { name: /close/i }).query())
      .toBeNull()
  })
})

"use client"

import type { RefObject } from "react"
import type { ToasterProps } from "sonner"
import type {
  HTMLStyledProps,
  NoticeCloseStrategy,
  NoticeConfig,
  NoticePlacement,
} from "@yamada-ui/react"
import type { CloseButtonProps } from "../close-button"
import type { Controller, NoticeMethods } from "./notice-provider"
import type { NoticeStyle } from "./notice.style"
import type { UseNoticeOptions } from "./use-notice"
import { useCallback, useMemo, useState } from "react"
import { toast, Toaster } from "sonner"
import { createSlotComponent, styled, assignRef, dataAttr, handlerAll, noop } from "@yamada-ui/react"
import { Alert } from "../alert"
import { CloseButton } from "../close-button"
import { useNoticeContext } from "./notice-provider"
import { noticeStyle } from "./notice.style"

type ToasterPosition = Required<ToasterProps>["position"]

export const PLACEMENT_MAP: {
  [key in NoticePlacement]: ToasterPosition
} = {
  end: "bottom-center",
  "end-center": "bottom-center",
  "end-end": "bottom-right",
  "end-start": "bottom-left",
  start: "top-center",
  "start-center": "top-center",
  "start-end": "top-right",
  "start-start": "top-left",
}

export interface NoticeRootProps extends Pick<
  Required<NoticeConfig>,
  "expand" | "limit" | "placement"
> {
  ref: RefObject<Controller>
}

const {
  PropsContext: NoticePropsContext,
  usePropsContext: useNoticePropsContext,
  withContext,
  withProvider,
} = createSlotComponent<NoticeRootProps, NoticeStyle>("notice", noticeStyle)

export { NoticePropsContext, useNoticePropsContext }

export const NoticeRoot = withProvider<"fragment", NoticeRootProps>(
  ({ ref, expand, limit, placement, ...rest }) => {
    const { getId } = useNoticeContext()
    const position = useMemo(() => PLACEMENT_MAP[placement], [placement])
    const [updatedLimit, setUpdatedLimit] = useState(limit)

    const getLimit = useCallback<NoticeMethods["getLimit"]>(
      (target) => {
        if (target === placement && updatedLimit !== limit) {
          return updatedLimit
        } else {
          return limit
        }
      },
      [placement, limit, updatedLimit],
    )

    const updateLimit = useCallback<NoticeMethods["updateLimit"]>(
      ({ limit, placement: target }) => {
        if (target === placement) setUpdatedLimit(limit)
      },
      [placement],
    )

    assignRef(ref.current.updateLimit, updateLimit)
    assignRef(ref.current.getLimit, getLimit)

    return (
      <styled.div {...rest}>
        <Toaster
          id={getId(placement)}
          containerAriaLabel=""
          expand={expand}
          gap={16}
          hotkey={[""]}
          mobileOffset="var(--mobile-offset)"
          offset="var(--offset)"
          position={position}
          visibleToasts={updatedLimit}
        />
      </styled.div>
    )
  },
  "root",
)()

export interface NoticeItemProps
  extends UseNoticeOptions, Omit<HTMLStyledProps, "id" | "title"> {
  closeStrategies?: NoticeCloseStrategy[]
}

export const NoticeItem = withContext<"div", NoticeItemProps>(
  ({
    id,
    variant = "plain",
    closable,
    closeStrategies = ["click", "drag"],
    description,
    loadingScheme,
    status,
    title,
    withIcon = true,
    closeButtonProps,
    contentProps,
    descriptionProps,
    iconProps,
    loadingProps,
    titleProps,
    onClick,
    ...rest
  }) => {
    const onClose = useCallback(() => toast.dismiss(id), [id])

    return (
      <Alert.Root
        variant={variant}
        status={status}
        {...rest}
        onClick={handlerAll(
          onClick,
          closable && closeStrategies.includes("click") ? onClose : noop,
        )}
      >
        {withIcon ? (
          loadingScheme ? (
            <Alert.Loading loadingScheme={loadingScheme} {...loadingProps} />
          ) : (
            <Alert.Icon {...iconProps} />
          )
        ) : null}

        <NoticeContent
          data-close-button={dataAttr(
            closable && closeStrategies.includes("button"),
          )}
          {...contentProps}
        >
          {title ? (
            <Alert.Title me="0" {...titleProps}>
              {title}
            </Alert.Title>
          ) : null}
          {description ? (
            <Alert.Description lineClamp={2} {...descriptionProps}>
              {description}
            </Alert.Description>
          ) : null}
        </NoticeContent>

        {closable && closeStrategies.includes("button") ? (
          <NoticeCloseButton
            data-variant={variant}
            {...closeButtonProps}
            onClick={handlerAll(closeButtonProps?.onClick, onClose)}
          />
        ) : null}
      </Alert.Root>
    )
  },
  "item",
)()

export interface NoticeContentProps extends HTMLStyledProps {}

export const NoticeContent = withContext<"div", NoticeContentProps>(
  "div",
  "content",
)()

export interface NoticeCloseButtonProps extends CloseButtonProps {}

export const NoticeCloseButton = withContext<"button", NoticeCloseButtonProps>(
  CloseButton,
  "closeButton",
)()

"use client"

import type { ReactNode } from "react"
import type { HTMLStyledProps, NoticeConfig } from "@yamada-ui/react"
import type { Alert } from "../alert"
import type { CloseButtonProps } from "../close-button"
import type { StatusScheme } from "../status"
import { useCallback, useMemo } from "react"
import { toast } from "sonner"
import { useSystem, isArray, omitObject } from "@yamada-ui/react"
import { NoticeItem } from "./notice"
import { useNoticeContext } from "./notice-provider"

export interface UseNoticeOptions
  extends
    Omit<NoticeConfig, "expand">,
    Omit<Alert.RootProps, "direction" | "id" | "status" | "title">,
    Pick<Alert.LoadingProps, "loadingScheme"> {
  /**
   * The description of the notice.
   */
  description?: ReactNode
  /**
   * Unique identifier for the notice.
   */
  id?: number | string
  /**
   * The status of the notice.
   */
  status?: StatusScheme
  /**
   * The title of the notice.
   */
  title?: ReactNode
  /**
   * If `true`, shows an icon.
   */
  withIcon?: boolean
  /**
   * Props for the close button.
   */
  closeButtonProps?: CloseButtonProps
  /**
   * Props for the content container.
   */
  contentProps?: HTMLStyledProps
  /**
   * Props for the description.
   */
  descriptionProps?: Alert.DescriptionProps
  /**
   * Props for the icon.
   */
  iconProps?: Alert.IconProps
  /**
   * Props for the loading component.
   */
  loadingProps?: Alert.LoadingProps
  /**
   * Props for the title.
   */
  titleProps?: Alert.TitleProps
}

export interface NoticeComponentProps {
  onClose: () => void
}

/**
 * `useNotice` is a custom hook that controls the notifications of the application using Sonner.
 *
 * @see https://yamada-ui.com/docs/hooks/use-notice
 */
export const useNotice = (options: UseNoticeOptions = {}) => {
  const { getId, getLimit, updateLimit } = useNoticeContext()
  const { config } = useSystem()

  const systemOptions = useMemo(
    () => omitObject(config.notice ?? {}, ["expand"]),
    [config],
  )
  const defaultOptions = useMemo(
    () => ({ ...systemOptions, ...options }),
    [options, systemOptions],
  )

  const getOptions = useCallback(
    (options: UseNoticeOptions) => ({ ...defaultOptions, ...options }),
    [defaultOptions],
  )

  return useMemo(() => {
    const notice = (options: UseNoticeOptions = {}) => {
      options = getOptions(options)

      const {
        closable = true,
        closeStrategy = ["click", "drag"],
        duration,
        limit = 3,
        placement = "start",
        ...props
      } = options

      if (limit) {
        const currentLimit = getLimit(placement)

        if (currentLimit !== limit) updateLimit({ limit, placement })
      }

      const closeStrategies = isArray(closeStrategy)
        ? closeStrategy
        : [closeStrategy]

      const resolvedOptions = {
        dismissible: closeStrategies.includes("drag") && closable,
        duration: duration ?? Number.POSITIVE_INFINITY,
        toasterId: getId(placement),
      }

      return toast.custom(
        (id) => (
          <NoticeItem
            {...props}
            id={id}
            closable={closable}
            closeStrategies={closeStrategies}
          />
        ),
        resolvedOptions,
      )
    }

    notice.close = (id: number | string) => toast.dismiss(id)

    notice.closeAll = () => toast.dismiss()

    notice.update = (id: number | string, options: UseNoticeOptions) => {
      toast.dismiss(id)

      return notice(options)
    }

    return notice
  }, [getLimit, getOptions, getId, updateLimit])
}

export type UseNoticeReturn = ReturnType<typeof useNotice>
